class Solution {
public:
    vector<bool> friendRequests(int n, vector<vector<int>>& restrictions, vector<vector<int>>& requests) {
        vector<bool> result;
        vector<vector<int>> graph(n);
        vector<bool> visited(n);
        vector<bool> restricted(n);

        for (auto& restriction : restrictions) {
            restricted[restriction[0]] = true;
            restricted[restriction[1]] = true;
        }

        for (int i = 0; i < requests.size(); i++) {
            int u = requests[i][0];
            int v = requests[i][1];
            if (restricted[u] || restricted[v]) {
                result.push_back(false);
                continue;
            }
            if (dfs(u, v, graph, visited)) {
                result.push_back(true);
            } else {
                result.push_back(false);
            }
        }
        return result;
    }

    bool dfs(int u, int v, vector<vector<int>>& graph, vector<bool>& visited) {
        if (u == v) return true;
        if (visited[u]) return false;
        visited[u] = true;
        for (int neighbor : graph[u]) {
            if (dfs(neighbor, v, graph, visited)) return true;
        }
        return false;
    }
};
```

